solution_code:
#include <iostream>

int main()
{
    int a {};
    int b {};
    std::cin >> a >> b;
    int& ref { a };
    int temp { ref };  // save original a
    ref = b;           // a = b
    b = temp;          // b = original a
    std::cout << "After swap: " << a << ' ' << b << '\n';
    return 0;
}
